var raw = $input.first().json;
var body = raw.body || raw;

function safe(s) { return String(s || '').replace(/'/g, "''").substring(0, 500); }
function safeInt(n, min, max) { var v = parseInt(n); return isNaN(v) ? min : Math.max(min, Math.min(max, v)); }

var token = safe(body.token).substring(0, 100);
var tenantId = safe(body.tenantId).substring(0, 36);
var leadId = safe(body.leadId).substring(0, 36);
var nom = safe(body.nom).substring(0, 100);
var prenom = safe(body.prenom).substring(0, 100);
var entreprise = safe(body.entreprise).substring(0, 200);
var email = safe(body.email).substring(0, 200);
var telephone = safe(body.telephone).substring(0, 20);
var note = safeInt(body.note, 1, 5);
var commentaire = safe(body.commentaire).substring(0, 2000);
var channel = ['telephone', 'email', 'web'].includes(body.channel) ? body.channel : 'web';

return [{ json: { token, tenantId, leadId, nom, prenom, entreprise, email, telephone, note, commentaire, channel } }];
